const M=['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const D=['Lun','Mar','Mie','Jue','Vie','Sab','Dom'];
let tecMap={}, yr=new Date().getFullYear(), mo=new Date().getMonth();
function pad(n){return String(n).padStart(2,'0')}
function buildMap(data){tecMap={};(data||[]).forEach(g=>{const s=new Date(g.fecha_inicio),e=new Date(g.fecha_fin);for(let d=new Date(s);d<=e;d.setDate(d.getDate()+1)){tecMap[d.toISOString().slice(0,10)]=g.tecnico}});}
function render(){document.getElementById('title').textContent=M[mo]+' '+yr;const grid=document.getElementById('grid');grid.innerHTML='';D.forEach((d,i)=>{const e=document.createElement('div');e.className='dlabel'+(i>=5?' wknd':'');e.textContent=d;grid.appendChild(e)});const fd=new Date(yr,mo,1).getDay(),off=fd===0?6:fd-1,dim=new Date(yr,mo+1,0).getDate(),today=new Date().toISOString().slice(0,10);for(let i=0;i<off;i++){const e=document.createElement('div');e.className='cell empty';grid.appendChild(e);}for(let d=1;d<=dim;d++){const ds=yr+'-'+pad(mo+1)+'-'+pad(d),isG=G.has(ds),tec=tecMap[ds],isT=(ds===today);const e=document.createElement('div');e.className='cell'+(isG||tec?' garzon':'')+(isT?' today':'');const n=document.createElement('div');n.className='daynum';n.textContent=d;e.appendChild(n);if(tec){const b=document.createElement('span');b.className='badge reg';b.textContent=tec;e.appendChild(b);}else if(isG){const b=document.createElement('span');b.className='badge';b.textContent='Garzon';e.appendChild(b);}grid.appendChild(e);}}
function go(dir){mo+=dir;if(mo<0){mo=11;yr--;}if(mo>11){mo=0;yr++;}render();}
